class Solution:
    def nextPermutation(self, nums):
        n = len(nums)
        i = n - 2
        while i >= 0 and nums[i + 1] <= nums[i]:
            i -= 1
        if i >= 0:
            best = -1
            for j in range(i + 1, n):
                if nums[j] > nums[i] and (best == -1 or nums[j] <= nums[best]):
                    best = j
            nums[i], nums[best] = nums[best], nums[i]
        suffix = sorted(nums[i + 1:])
        nums[i + 1:] = suffix

